from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os
import pickle

app = Flask(__name__)

# Load or train the model
def train_model(training_directory='employee_photos'):
    known_face_encodings = []
    known_face_names = []

    for filename in os.listdir(training_directory):
        if filename.endswith('.jpg') or filename.endswith('.png'):
            image_path = os.path.join(training_directory, filename)
            image = face_recognition.load_image_file(image_path)
            encoding = face_recognition.face_encodings(image)
            if encoding:
                known_face_encodings.append(encoding[0])
                known_face_names.append(os.path.splitext(filename)[0])

    with open('trained_model.pkl', 'wb') as f:
        pickle.dump((known_face_encodings, known_face_names), f)

def load_model():
    with open('trained_model.pkl', 'rb') as f:
        return pickle.load(f)

# Train model if not already trained
if not os.path.exists('trained_model.pkl'):
    train_model()

known_face_encodings, known_face_names = load_model()

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)

    if not face_encodings:
        return jsonify({'error': 'No faces found'}), 400

    face_encoding = face_encodings[0]
    face_distances = face_recognition.face_distance(known_face_encodings, face_encoding)
    face_probabilities = 1 - face_distances
    face_probabilities = face_probabilities / np.sum(face_probabilities)

    results = {name: float(prob) for name, prob in zip(known_face_names, face_probabilities)}

    return jsonify(results)

if __name__ == '__main__':
    app.run(ssl_context='adhoc')